+        prop_assert_eq!(cloned.observed, item.observed);
+        prop_assert_eq!(cloned.ignore_reason, item.ignore_reason);
+        prop_assert_eq!(cloned.domain, item.domain);
+    }
+
+    /// GapInfo Clone preserves all fields.
